/*
 * OCR A-Level Physics A (H556) — Exam Practice Question Bank
 * All written/exam-style questions with OCR command words and mark schemes.
 * 50 questions per topic (25 for M1), varying from 1-mark to 8-mark questions.
 */

const PHYSICS_OCR_A_PRACTICE = {

  /* ─────────────────────────────────────────────────────────── M1 */
  'M1': {
    name: 'Practical Skills in Physics',
    questions: [
      { q: 'State what is meant by a systematic error.', marks: 1, markScheme: `• A consistent error in the same direction that affects all readings by the same amount (1)` },
      { q: 'State what is meant by a random error.', marks: 1, markScheme: `• An unpredictable variation between measurements that causes readings to scatter around the true value (1)` },
      { q: 'State the difference between accuracy and precision.', marks: 2, markScheme: `• Accuracy: how close a measurement is to the true/accepted value (1)\n• Precision: how close repeated measurements are to each other / the spread of readings (1)` },
      { q: 'State what is meant by the resolution of an instrument.', marks: 1, markScheme: `• The smallest change in the measured quantity that the instrument can detect (1)` },
      { q: 'A student measures a length as 0.45 m with an uncertainty of ±0.01 m. Calculate the percentage uncertainty.', marks: 2, markScheme: `• Percentage uncertainty = (0.01 / 0.45) × 100 (1)\n• = 2.2% (1)` },
      { q: 'Explain how repeating measurements helps improve the reliability of an experiment.', marks: 2, markScheme: `• Repeating measurements allows the identification and removal of anomalous results (1)\n• Taking a mean of repeated readings reduces the effect of random errors, making the result more reliable (1)` },
      { q: 'A student measures the time for 20 oscillations of a pendulum as 32.4 ± 0.2 s. Calculate the period and its absolute uncertainty.', marks: 3, markScheme: `• Period T = 32.4 / 20 = 1.62 s (1)\n• Absolute uncertainty in T = 0.2 / 20 = 0.01 s (1)\n• T = 1.62 ± 0.01 s (1)` },
      { q: 'Describe how to draw an appropriate line of best fit on a scatter graph.', marks: 2, markScheme: `• Draw a straight line (or smooth curve if the trend is non-linear) that passes as close to as many data points as possible (1)\n• There should be roughly equal numbers of points above and below the line, and outliers/anomalies should be ignored (1)` },
      { q: 'Explain why a graph of T² against l should be plotted rather than T against l when investigating a pendulum.', marks: 2, markScheme: `• The equation T = 2π√(l/g) gives T² = (4π²/g)l (1)\n• Plotting T² against l gives a straight line through the origin, making it easier to verify the relationship and determine g from the gradient (1)` },
      { q: 'State two ways to reduce systematic errors in an experiment.', marks: 2, markScheme: `• Calibrate the instrument against a known standard before use (1)\n• Use a different measurement technique or instrument to cross-check results (1)` },
      { q: 'A student calculates speed from v = s/t. The percentage uncertainty in s is 3% and in t is 2%. Calculate the percentage uncertainty in v.', marks: 2, markScheme: `• When dividing, percentage uncertainties are added (1)\n• %Δv = 3% + 2% = 5% (1)` },
      { q: 'Explain how error bars are used on a graph and how they help determine the uncertainty in the gradient.', marks: 3, markScheme: `• Error bars are vertical (and/or horizontal) lines drawn on each data point showing the range of uncertainty in the measurement (1)\n• The steepest and shallowest lines of best fit that pass through all the error bars are drawn (1)\n• The uncertainty in the gradient = (steepest gradient − shallowest gradient) / 2 (1)` },
      { q: 'A quantity is given by P = kd³ where d has a percentage uncertainty of 4%. Calculate the percentage uncertainty in P.', marks: 2, markScheme: `• When a quantity is raised to a power, the percentage uncertainty is multiplied by that power (1)\n• %ΔP = 3 × 4% = 12% (1)` },
      { q: 'Describe one method for reducing random errors when measuring the diameter of a thin wire.', marks: 2, markScheme: `• Measure the diameter at several different positions along the wire and at different orientations using a micrometer (1)\n• Calculate the mean of these readings to reduce the effect of random variations (1)` },
      { q: 'Explain why it is important to identify and control variables in an experiment.', marks: 2, markScheme: `• Control variables must be kept constant to ensure that any change in the dependent variable is due only to changes in the independent variable (fair test) (1)\n• Failure to control variables means results may be invalid — changes could be caused by confounding factors (1)` },
      { q: 'A student plots a graph and obtains the equation y = mx + c. State what information can be obtained from the gradient and the y-intercept.', marks: 2, markScheme: `• The gradient m represents the rate of change of y with respect to x / the constant of proportionality in the relationship (1)\n• The y-intercept c represents the value of y when x = 0 — this may correspond to a physical constant or initial value (1)` },
      { q: 'A log-log graph of y against x gives a straight line with gradient 0.5 and y-intercept 1.2. Determine the relationship between y and x.', marks: 3, markScheme: `• A log-log graph of the form log y = n log x + log k gives gradient n and intercept log k (1)\n• Gradient = 0.5, so n = 0.5, meaning y ∝ x^0.5 = √x (1)\n• y-intercept = log k = 1.2, so k = 10^1.2 ≈ 15.8; therefore y = 15.8√x (1)` },
      { q: 'Explain the purpose of plotting a graph of ln y against x when the expected relationship is y = Ae^(kx).', marks: 3, markScheme: `• Taking natural logs: ln y = ln A + kx (1)\n• This is in the form Y = c + mX — a straight-line equation (1)\n• The gradient gives k and the y-intercept gives ln A, from which A can be determined (1)` },
      { q: 'A student obtains a value of g = 9.65 ± 0.25 m s⁻². The accepted value is 9.81 m s⁻². Evaluate whether the result is consistent with the accepted value.', marks: 3, markScheme: `• The range of the result is 9.40 to 9.90 m s⁻² (1)\n• The accepted value 9.81 falls within this range (1)\n• Therefore the result is consistent with the accepted value within the stated uncertainty (1)` },
      { q: 'Describe the steps involved in planning an experiment to investigate how the angle of launch affects the range of a projectile.', marks: 4, markScheme: `• Independent variable: launch angle; dependent variable: range (horizontal distance); control variables: launch speed, height of launch, same projectile (1)\n• Use a launcher that allows the angle to be varied while keeping the launch speed constant (e.g. a spring-loaded launcher) (1)\n• Measure the range for angles from 10° to 80° in suitable increments (e.g. 10°), repeating each measurement at least 3 times (1)\n• Plot a graph of range against angle and compare with the theoretical prediction that maximum range occurs at 45° (1)` },
      { q: 'Explain why measurements should be given to an appropriate number of significant figures.', marks: 2, markScheme: `• The number of significant figures should reflect the precision of the measuring instrument used (1)\n• Giving too many significant figures implies a false level of precision; too few loses information about the measurement (1)` },
      { q: 'State two advantages of using a data logger compared to manual measurements.', marks: 2, markScheme: `• Data loggers can take readings at much faster rates / shorter time intervals than a human (1)\n• They eliminate human reaction time errors and can record data continuously over long periods (1)` },
      { q: 'A student measures the acceleration due to gravity using a free-fall method. Suggest two sources of error and explain how each could be minimised.', marks: 4, markScheme: `• Source 1: Reaction time when starting/stopping a stopwatch — minimise by using electronic timing (light gates) or electromagnet release (1)\n• This eliminates the systematic error caused by human reaction time (1)\n• Source 2: Air resistance on the falling object — minimise by using a dense, compact object (e.g. steel ball bearing) to reduce drag (1)\n• Using a larger drop distance increases the total time, reducing the percentage effect of any timing error (1)` },
      { q: 'Explain why the uncertainty in a measurement using a stopwatch is usually much larger than the resolution of the stopwatch.', marks: 2, markScheme: `• The resolution of a digital stopwatch is typically 0.01 s, but human reaction time is approximately 0.2–0.3 s (1)\n• The dominant uncertainty is the reaction time at both the start and stop, making the total uncertainty much larger than the instrument resolution (1)` },
      { q: 'Discuss the importance of evaluating an experiment. Describe what a good evaluation should include.', marks: 4, markScheme: `• Compare the experimental result with the accepted value — calculate the percentage difference (1)\n• Compare the percentage difference with the total percentage uncertainty — if the percentage difference is within the total uncertainty, the result is consistent with theory (1)\n• Identify the largest sources of uncertainty and suggest which measurement contributes most to the total uncertainty (1)\n• Suggest specific, practical improvements to reduce the largest uncertainties and any systematic errors identified (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── M2 */
  'M2': {
    name: 'Foundations of Physics',
    questions: [
      { q: 'State the seven SI base quantities and their units.', marks: 3, markScheme: `• Mass — kilogram (kg); Length — metre (m); Time — second (s) (1)\n• Electric current — ampere (A); Temperature — kelvin (K) (1)\n• Amount of substance — mole (mol); Luminous intensity — candela (cd) (1)` },
      { q: 'Define the term "derived unit" and give two examples.', marks: 2, markScheme: `• A derived unit is one that is made from combinations of SI base units through multiplication or division (1)\n• Examples: newton (N) = kg m s⁻²; joule (J) = kg m² s⁻²; pascal (Pa) = kg m⁻¹ s⁻²; watt (W) = kg m² s⁻³ (any two) (1)` },
      { q: 'Express the volt in SI base units.', marks: 2, markScheme: `• Volt = J/C = (kg m² s⁻²) / (A s) (1)\n• = kg m² s⁻³ A⁻¹ (1)` },
      { q: 'Express the ohm in SI base units.', marks: 2, markScheme: `• Ohm = V/A = (kg m² s⁻³ A⁻¹) / A (1)\n• = kg m² s⁻³ A⁻² (1)` },
      { q: 'State the difference between a scalar and a vector quantity. Give two examples of each.', marks: 3, markScheme: `• A scalar has magnitude only; a vector has both magnitude and direction (1)\n• Scalars: speed, mass, energy, temperature, distance (any two) (1)\n• Vectors: velocity, force, displacement, acceleration, momentum (any two) (1)` },
      { q: 'Convert 45 nm to metres.', marks: 1, markScheme: `• 45 nm = 45 × 10⁻⁹ m = 4.5 × 10⁻⁸ m (1)` },
      { q: 'Convert 3.7 GHz to Hz.', marks: 1, markScheme: `• 3.7 GHz = 3.7 × 10⁹ Hz (1)` },
      { q: 'State what is meant by the homogeneity of a physical equation.', marks: 1, markScheme: `• An equation is homogeneous if every term has the same SI base units / dimensions (1)` },
      { q: 'Check whether the equation v = u + at is homogeneous.', marks: 3, markScheme: `• Units of v: m s⁻¹ (1)\n• Units of u: m s⁻¹; units of at: (m s⁻²)(s) = m s⁻¹ (1)\n• All terms have units of m s⁻¹, so the equation is homogeneous (1)` },
      { q: 'Show that the equation for kinetic energy E = ½mv² is homogeneous.', marks: 2, markScheme: `• Units of E: joule = kg m² s⁻² (1)\n• Units of ½mv²: kg × (m s⁻¹)² = kg m² s⁻² — units match, so the equation is homogeneous (1)` },
      { q: 'Explain why checking homogeneity cannot prove that an equation is correct.', marks: 2, markScheme: `• Homogeneity checks cannot detect incorrect dimensionless constants (e.g. cannot distinguish ½mv² from mv²) (1)\n• The equation may be missing a term that has the same units as the existing terms (1)` },
      { q: 'A force of 8.0 N acts at 40° to the horizontal. Calculate the horizontal and vertical components.', marks: 3, markScheme: `• Horizontal: F cos 40° = 8.0 × cos 40° = 6.1 N (1)\n• Vertical: F sin 40° = 8.0 × sin 40° = 5.1 N (1)\n• Both components correctly calculated with appropriate significant figures (1)` },
      { q: 'Two forces of 5.0 N and 12.0 N act at right angles to each other. Calculate the magnitude and direction of the resultant.', marks: 3, markScheme: `• Magnitude: R = √(5² + 12²) = √(169) = 13.0 N (1)\n• Direction: θ = tan⁻¹(5/12) = 22.6° to the 12 N force (1)\n• Correct use of Pythagoras and trigonometry (1)` },
      { q: 'A vector A of magnitude 10 N acts at 30° above the horizontal. Resolve it into components.', marks: 2, markScheme: `• Horizontal component: 10 cos 30° = 8.7 N (1)\n• Vertical component: 10 sin 30° = 5.0 N (1)` },
      { q: 'Estimate the order of magnitude of the number of seconds in a human lifetime.', marks: 2, markScheme: `• Assume lifetime ≈ 80 years; 80 × 365 × 24 × 3600 ≈ 2.5 × 10⁹ s (1)\n• Order of magnitude ≈ 10⁹ s (1)` },
      { q: 'Estimate the number of golf balls that would fit inside a typical classroom.', marks: 3, markScheme: `• Estimate classroom volume: 10 m × 8 m × 3 m = 240 m³ (1)\n• Estimate golf ball volume: radius ≈ 0.02 m, V = (4/3)π(0.02)³ ≈ 3.4 × 10⁻⁵ m³ (1)\n• Number ≈ 240 / 3.4 × 10⁻⁵ ≈ 7 × 10⁶ — order of magnitude 10⁷ (accounting for packing efficiency ~64%) (1)` },
      { q: 'The drag force on a sphere is F = 6πηrv. Verify that the equation is homogeneous, given that η (viscosity) has units Pa s.', marks: 3, markScheme: `• Units of F: N = kg m s⁻² (1)\n• Units of η: Pa s = (kg m⁻¹ s⁻²)(s) = kg m⁻¹ s⁻¹; units of r: m; units of v: m s⁻¹ (1)\n• Units of 6πηrv = (kg m⁻¹ s⁻¹)(m)(m s⁻¹) = kg m s⁻² — same as N, so homogeneous (1)` },
      { q: 'A boat travels 5 km north and then 8 km east. Calculate the magnitude and direction of the displacement.', marks: 3, markScheme: `• Magnitude: √(5² + 8²) = √(89) = 9.4 km (1)\n• Direction: θ = tan⁻¹(8/5) = 58° east of north (or bearing 058°) (1)\n• Correct calculation and clear statement of direction (1)` },
      { q: 'Explain the process of adding two vectors using a scale diagram.', marks: 3, markScheme: `• Draw the first vector to scale in the correct direction (1)\n• Draw the second vector starting from the tip of the first, to scale and in the correct direction (tip-to-tail method) (1)\n• The resultant is the vector from the start of the first to the tip of the second; measure its length and angle from the diagram (1)` },
      { q: 'State the prefix and multiplier for each of the following: pico, kilo, giga, femto.', marks: 2, markScheme: `• pico (p) = 10⁻¹²; kilo (k) = 10³ (1)\n• giga (G) = 10⁹; femto (f) = 10⁻¹⁵ (1)` },
      { q: 'A student derives an equation for the speed of waves on a string: v = √(T/μ) where T is tension (N) and μ is mass per unit length (kg m⁻¹). Show this is dimensionally consistent.', marks: 3, markScheme: `• Units of v: m s⁻¹ (1)\n• Units of T/μ: (kg m s⁻²) / (kg m⁻¹) = m² s⁻² (1)\n• Units of √(T/μ) = m s⁻¹ — matches v, so dimensionally consistent (1)` },
      { q: 'Two forces of equal magnitude F act on a point at an angle of 120° to each other. Show that the resultant has magnitude F.', marks: 3, markScheme: `• Using the cosine rule: R² = F² + F² + 2F² cos 120° (1)\n• R² = 2F² + 2F²(−0.5) = 2F² − F² = F² (1)\n• Therefore R = F (1)` },
      { q: 'Explain why displacement is a vector but distance is a scalar.', marks: 2, markScheme: `• Displacement specifies how far and in what direction an object is from its starting point — it has both magnitude and direction (1)\n• Distance only measures the total path length travelled regardless of direction — it has magnitude only (1)` },
      { q: 'Calculate the resultant of three forces: 10 N east, 6 N north, and 4 N west.', marks: 3, markScheme: `• Horizontal component: 10 − 4 = 6 N east (1)\n• Vertical component: 6 N north (1)\n• Resultant: √(6² + 6²) = √72 = 8.5 N at 45° north of east (1)` },
      { q: 'Explain what is meant by an order of magnitude estimate and why such estimates are useful in physics.', marks: 2, markScheme: `• An order of magnitude estimate gives a value rounded to the nearest power of 10, using reasonable assumptions (1)\n• They are useful for checking whether a calculated answer is sensible, for planning experiments, and for comparing quantities that differ by large factors (1)` },
      { q: 'State what is meant by the term "base unit" and explain why SI base units are important in physics.', marks: 2, markScheme: `• A base unit is a fundamental unit that is not derived from any other units — it is defined by a physical standard or constant (1)\n• SI base units provide a universal, consistent system of measurement that allows physicists worldwide to communicate results unambiguously (1)` },
      { q: 'Express the unit of the gravitational constant G in SI base units, given F = GMm/r².', marks: 3, markScheme: `• Rearranging: G = Fr²/(Mm) (1)\n• Units: (kg m s⁻²)(m²) / (kg)(kg) = kg m³ s⁻² / kg² (1)\n• G has units: m³ kg⁻¹ s⁻² (or equivalently N m² kg⁻²) (1)` },
      { q: 'A velocity of 72 km h⁻¹ needs to be converted to m s⁻¹. Show the conversion.', marks: 2, markScheme: `• 72 km h⁻¹ = 72 × 1000 / 3600 (1)\n• = 20 m s⁻¹ (1)` },
      { q: 'Explain, with an example, why a physical equation that is homogeneous may still contain an error.', marks: 3, markScheme: `• A homogeneous equation has matching units on both sides, but this does not guarantee correctness (1)\n• Dimensionless constants cannot be checked: e.g. both E = mv² and E = ½mv² have units kg m² s⁻² (1)\n• Therefore homogeneity is a necessary condition for correctness but not a sufficient one (1)` },
      { q: 'Two vectors P and Q have magnitudes 7 N and 3 N respectively. State the maximum and minimum possible magnitudes of the resultant P + Q.', marks: 2, markScheme: `• Maximum (same direction): 7 + 3 = 10 N (1)\n• Minimum (opposite direction): 7 − 3 = 4 N (1)` },
      { q: 'The period of a mass-spring system is T = 2π√(m/k). Use dimensional analysis to find the units of the spring constant k.', marks: 3, markScheme: `• T has units of s; m has units of kg (1)\n• From T = 2π√(m/k): T² = 4π²m/k, so k = 4π²m/T² (1)\n• Units of k = kg / s² = kg s⁻² (which is equivalent to N m⁻¹) (1)` },
      { q: 'Estimate the power of a person running up a flight of stairs.', marks: 3, markScheme: `• Assume mass ≈ 70 kg, height of stairs ≈ 3 m, time ≈ 5 s (1)\n• Work done = mgh = 70 × 10 × 3 = 2100 J (1)\n• Power = W/t = 2100 / 5 = 420 W ≈ order of magnitude 10² W (1)` },
      { q: 'A force of 15 N acts at angle θ to the horizontal. The horizontal component is 12 N. Calculate the angle θ and the vertical component.', marks: 3, markScheme: `• cos θ = 12/15 = 0.8, so θ = cos⁻¹(0.8) = 36.9° (1)\n• Vertical component = 15 sin 36.9° = 9.0 N (1)\n• Or using Pythagoras: √(15² − 12²) = √(81) = 9.0 N (1)` },
      { q: 'Three coplanar forces act on a point: 10 N at 0°, 8 N at 90°, and 5 N at 210°. Calculate the resultant.', marks: 4, markScheme: `• x-components: 10 cos 0° + 8 cos 90° + 5 cos 210° = 10 + 0 + (−4.33) = 5.67 N (1)\n• y-components: 10 sin 0° + 8 sin 90° + 5 sin 210° = 0 + 8 + (−2.5) = 5.5 N (1)\n• Resultant magnitude: √(5.67² + 5.5²) = √(62.4) = 7.9 N (1)\n• Direction: θ = tan⁻¹(5.5/5.67) = 44.1° above the horizontal (1)` },
      { q: 'Explain why the weight of an object is a vector but its mass is a scalar.', marks: 2, markScheme: `• Weight is a force (W = mg) that acts in a specific direction (towards the centre of the Earth), so it has both magnitude and direction — it is a vector (1)\n• Mass is a measure of the quantity of matter in an object and has no direction associated with it — it is a scalar (1)` },
      { q: 'State the SI base units of energy and verify that 1 eV = 1.6 × 10⁻¹⁹ J.', marks: 3, markScheme: `• SI base units of energy: kg m² s⁻² (1)\n• 1 eV is the energy gained by an electron (charge 1.6 × 10⁻¹⁹ C) moving through a PD of 1 V (1)\n• E = QV = 1.6 × 10⁻¹⁹ × 1 = 1.6 × 10⁻¹⁹ J (1)` },
      { q: 'A satellite orbits Earth. The centripetal acceleration is given by a = v²/r. Express the units of v²/r in SI base units and confirm they are the units of acceleration.', marks: 2, markScheme: `• Units of v²/r = (m s⁻¹)² / m = m² s⁻² / m = m s⁻² (1)\n• This is the unit of acceleration, confirming dimensional consistency (1)` },
      { q: 'Estimate the mass of air in a typical classroom.', marks: 3, markScheme: `• Estimate volume: 10 × 8 × 3 = 240 m³ (1)\n• Density of air ≈ 1.2 kg m⁻³ (1)\n• Mass = ρV = 1.2 × 240 ≈ 290 kg, order of magnitude 10² kg (1)` },
      { q: 'Explain the difference between a physical quantity being measured in SI units and being expressed in SI base units.', marks: 2, markScheme: `• A measurement in SI units can use any recognised SI unit, including derived units (e.g. newtons, joules, watts) (1)\n• Expressing in SI base units means writing the unit purely in terms of kg, m, s, A, K, mol, and cd (e.g. newton becomes kg m s⁻²) (1)` },
      { q: 'A student resolves a velocity of 25 m s⁻¹ at 53° to the horizontal. Calculate both components and verify using Pythagoras\' theorem.', marks: 3, markScheme: `• Horizontal: 25 cos 53° = 15.0 m s⁻¹; Vertical: 25 sin 53° = 20.0 m s⁻¹ (1)\n• Check: √(15² + 20²) = √(225 + 400) = √625 = 25 m s⁻¹ ✓ (1)\n• Both components correct with verification shown (1)` },
      { q: 'A hiker walks 4.0 km on a bearing of 060° and then 3.0 km on a bearing of 150°. Calculate the magnitude and bearing of the total displacement.', marks: 4, markScheme: `• First leg: east component = 4.0 sin 60° = 3.46 km; north component = 4.0 cos 60° = 2.0 km (1)\n• Second leg: east component = 3.0 sin 150° = 1.5 km; north component = 3.0 cos 150° = −2.60 km (1)\n• Total east = 4.96 km; total north = −0.60 km; magnitude = √(4.96² + 0.60²) = 5.0 km (1)\n• Bearing = 90° + tan⁻¹(0.60/4.96) = 97° (or equivalently 083° + correction — approximately bearing 097°) (1)` },
      { q: 'Discuss the advantages and limitations of using SI units as a universal measurement system.', marks: 4, markScheme: `• Advantage: provides consistency — all scientists worldwide use the same units, allowing results to be compared and reproduced (1)\n• Advantage: base units are now defined by fundamental constants (e.g. speed of light, Planck constant), making them stable and reproducible (1)\n• Limitation: some derived units can be unfamiliar or counterintuitive (e.g. Pa = kg m⁻¹ s⁻²) (1)\n• Limitation: everyday contexts sometimes favour non-SI units (e.g. eV in particle physics, light-years in astronomy) for practical convenience (1)` },
      { q: 'Use dimensional analysis to determine how the frequency f of a vibrating string might depend on its length L, tension T (in N), and mass per unit length μ (in kg m⁻¹).', marks: 4, markScheme: `• Assume f = k × L^a × T^b × μ^c where k is dimensionless (1)\n• Dimensions: [f] = s⁻¹; [L] = m; [T] = kg m s⁻²; [μ] = kg m⁻¹ (1)\n• Equating dimensions: s⁻¹ = m^a × (kg m s⁻²)^b × (kg m⁻¹)^c → for kg: 0 = b + c; for m: 0 = a + b − c; for s: −1 = −2b (1)\n• Solving: b = ½, c = −½, a = −1; so f = k/(L) × √(T/μ) — consistent with f = (1/2L)√(T/μ) (1)` },
      { q: 'A uniform electric field has units V m⁻¹. Express this in SI base units.', marks: 2, markScheme: `• V m⁻¹ = (kg m² s⁻³ A⁻¹) × m⁻¹ (1)\n• = kg m s⁻³ A⁻¹ (1)` },
      { q: 'Calculate the resultant of two equal forces of 20 N acting at 90° to each other.', marks: 2, markScheme: `• R = √(20² + 20²) = √800 = 28.3 N (1)\n• Direction: 45° to either force (by symmetry) (1)` },
      { q: 'State what is meant by equilibrium of forces and describe the conditions for a body to be in static equilibrium.', marks: 3, markScheme: `• Equilibrium of forces means the resultant force on the body is zero (1)\n• For static equilibrium: the vector sum of all forces is zero (translational equilibrium) (1)\n• The sum of all moments/torques about any point is also zero (rotational equilibrium) (1)` },
      { q: 'Explain what is meant by the resolution of a vector and why it is a useful technique.', marks: 2, markScheme: `• Resolution is the process of splitting a single vector into two perpendicular components (usually horizontal and vertical) (1)\n• It is useful because perpendicular components can be treated independently, simplifying calculations involving forces, velocities, or displacements at angles (1)` },
      { q: 'Estimate the number of atoms along the length of a 30 cm ruler, given that an atomic diameter is approximately 10⁻¹⁰ m.', marks: 2, markScheme: `• Length = 0.30 m; atomic diameter ≈ 10⁻¹⁰ m (1)\n• Number = 0.30 / 10⁻¹⁰ = 3 × 10⁹ atoms (1)` },
      { q: 'A pendulum has length 0.80 m. Use g = 9.81 m s⁻² to calculate the period using T = 2π√(l/g), and state your answer to an appropriate number of significant figures.', marks: 3, markScheme: `• T = 2π√(0.80/9.81) = 2π√(0.08155) = 2π × 0.2856 (1)\n• T = 1.795 s (1)\n• Rounded to 2 s.f. (matching the 2 s.f. in l = 0.80): T = 1.8 s (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── M3 */
  'M3': {
    name: 'Forces and Motion',
    questions: [
      { q: 'State Newton\'s first law of motion.', marks: 1, markScheme: `• An object remains at rest or continues to move at constant velocity unless acted upon by a resultant force (1)` },
      { q: 'State Newton\'s second law of motion in terms of momentum.', marks: 1, markScheme: `• The resultant force acting on an object equals the rate of change of its momentum: F = Δp/Δt (1)` },
      { q: 'State Newton\'s third law of motion.', marks: 2, markScheme: `• When body A exerts a force on body B, body B exerts an equal and opposite force on body A (1)\n• The forces are of the same type and act on different objects (1)` },
      { q: 'Define velocity.', marks: 1, markScheme: `• Velocity is the rate of change of displacement (a vector quantity) (1)` },
      { q: 'Define acceleration.', marks: 1, markScheme: `• Acceleration is the rate of change of velocity (1)` },
      { q: 'State the principle of conservation of momentum.', marks: 2, markScheme: `• In a closed system with no external forces (1)\n• The total momentum before an event equals the total momentum after the event (1)` },
      { q: 'A car accelerates uniformly from 10 m s⁻¹ to 30 m s⁻¹ in 8 s. Calculate the acceleration.', marks: 2, markScheme: `• a = (v − u) / t = (30 − 10) / 8 (1)\n• a = 2.5 m s⁻² (1)` },
      { q: 'An object starts from rest and accelerates at 3 m s⁻² for 6 s. Calculate the distance travelled.', marks: 2, markScheme: `• s = ut + ½at² = 0 + ½ × 3 × 36 (1)\n• s = 54 m (1)` },
      { q: 'A ball is thrown vertically upward at 20 m s⁻¹. Calculate the maximum height reached. (g = 9.81 m s⁻²)', marks: 2, markScheme: `• Using v² = u² + 2as with v = 0: 0 = 400 − 2(9.81)s (1)\n• s = 400 / 19.62 = 20.4 m (1)` },
      { q: 'Describe what a displacement-time graph shows for an object moving at constant velocity.', marks: 2, markScheme: `• A straight line with a positive (or negative) gradient (1)\n• The gradient equals the constant velocity of the object (1)` },
      { q: 'Describe what a velocity-time graph shows for an object undergoing uniform acceleration.', marks: 2, markScheme: `• A straight line with a positive gradient (1)\n• The gradient equals the acceleration and the area under the graph gives the displacement (1)` },
      { q: 'A stone is dropped from a bridge 45 m above a river. Calculate the time to reach the water. (g = 9.81 m s⁻²)', marks: 2, markScheme: `• s = ½gt²: 45 = ½ × 9.81 × t² (1)\n• t² = 9.17, t = 3.03 s ≈ 3.0 s (1)` },
      { q: 'A ball is projected horizontally at 12 m s⁻¹ from a 20 m high cliff. Calculate the time of flight and the horizontal distance travelled. (g = 9.81 m s⁻²)', marks: 3, markScheme: `• Time: 20 = ½ × 9.81 × t², t = 2.02 s (1)\n• Horizontal distance = 12 × 2.02 = 24.2 m (1)\n• Horizontal and vertical motions treated independently (1)` },
      { q: 'Explain why the horizontal velocity of a projectile remains constant (in the absence of air resistance).', marks: 2, markScheme: `• There is no horizontal force acting on the projectile (air resistance is negligible) (1)\n• By Newton\'s first law, the horizontal velocity remains constant when there is no resultant force in that direction (1)` },
      { q: 'A 1500 kg car brakes from 25 m s⁻¹ to rest in 50 m. Calculate the braking force.', marks: 3, markScheme: `• Using v² = u² + 2as: 0 = 625 + 2a(50), a = −6.25 m s⁻² (1)\n• F = ma = 1500 × 6.25 (1)\n• F = 9375 N ≈ 9400 N (1)` },
      { q: 'A 5.0 kg trolley moving at 3.0 m s⁻¹ collides with a stationary 3.0 kg trolley. They stick together. Calculate the velocity after the collision.', marks: 2, markScheme: `• m₁u₁ = (m₁ + m₂)v: 5.0 × 3.0 = 8.0 × v (1)\n• v = 15/8 = 1.875 m s⁻¹ ≈ 1.9 m s⁻¹ (1)` },
      { q: 'Define impulse and explain its relationship to momentum.', marks: 2, markScheme: `• Impulse = force × time = FΔt (1)\n• Impulse equals the change in momentum: FΔt = Δp = mv − mu (1)` },
      { q: 'A cricket ball of mass 0.16 kg is struck by a bat. Its velocity changes from 30 m s⁻¹ to −20 m s⁻¹ in 0.003 s. Calculate the average force.', marks: 3, markScheme: `• Change in momentum = 0.16 × (−20 − 30) = 0.16 × (−50) = −8.0 kg m s⁻¹ (1)\n• F = Δp / Δt = 8.0 / 0.003 (1)\n• F = 2667 N ≈ 2700 N (1)` },
      { q: 'Explain what is meant by terminal velocity and state the condition for it to be reached.', marks: 2, markScheme: `• Terminal velocity is the constant velocity reached when the drag force equals the driving force (or weight for a falling object) (1)\n• At terminal velocity the resultant force is zero, so by Newton\'s second law the acceleration is zero (1)` },
      { q: 'A 70 kg skydiver falls from a plane. Describe how the forces and velocity change during the fall until terminal velocity is reached.', marks: 4, markScheme: `• Initially: weight >> drag, so there is a large downward resultant force and the skydiver accelerates rapidly (1)\n• As speed increases, drag force increases (drag depends on velocity) (1)\n• The resultant force decreases, so the rate of acceleration decreases (1)\n• Eventually drag equals weight (687 N), resultant force is zero, and the skydiver moves at constant terminal velocity (1)` },
      { q: 'Calculate the work done when a force of 40 N pulls a box 8 m along a horizontal floor at 25° to the horizontal.', marks: 2, markScheme: `• W = Fs cos θ = 40 × 8 × cos 25° (1)\n• W = 290 J (1)` },
      { q: 'A 2.0 kg ball is dropped from a height of 5.0 m. Calculate its speed just before hitting the ground, assuming no air resistance. (g = 9.81 m s⁻²)', marks: 2, markScheme: `• Using conservation of energy: ½mv² = mgh, v = √(2gh) = √(2 × 9.81 × 5.0) (1)\n• v = 9.9 m s⁻¹ (1)` },
      { q: 'Define power and give two equations for power.', marks: 2, markScheme: `• Power is the rate of doing work or the rate of energy transfer (1)\n• P = W/t and P = Fv (where F is force and v is velocity in the direction of the force) (1)` },
      { q: 'A car engine exerts a driving force of 3000 N while travelling at a constant 20 m s⁻¹. Calculate the power output.', marks: 2, markScheme: `• P = Fv = 3000 × 20 (1)\n• P = 60 000 W = 60 kW (1)` },
      { q: 'Define efficiency and explain why no machine can be 100% efficient.', marks: 2, markScheme: `• Efficiency = (useful output energy or power / total input energy or power) × 100% (1)\n• Some energy is always transferred to thermal energy (heat) due to friction or resistance — this is unavoidable and reduces the useful output below the input (1)` },
      { q: 'A machine has an input power of 2.0 kW and an output power of 1.6 kW. Calculate its efficiency.', marks: 2, markScheme: `• Efficiency = (1600 / 2000) × 100% (1)\n• = 80% (1)` },
      { q: 'A 0.2 kg ball is released from rest and falls 1.8 m onto a surface. It bounces back to a height of 1.2 m. Calculate the energy lost during the bounce.', marks: 3, markScheme: `• GPE before = mgh = 0.2 × 9.81 × 1.8 = 3.53 J (1)\n• GPE after = 0.2 × 9.81 × 1.2 = 2.35 J (1)\n• Energy lost = 3.53 − 2.35 = 1.18 J ≈ 1.2 J (1)` },
      { q: 'A bullet of mass 0.01 kg travelling at 300 m s⁻¹ embeds in a stationary block of mass 2 kg on a frictionless surface. Calculate the velocity of the block after the collision and the kinetic energy lost.', marks: 4, markScheme: `• Conservation of momentum: 0.01 × 300 = (0.01 + 2) × v, v = 3/2.01 = 1.49 m s⁻¹ (1)\n• KE before = ½ × 0.01 × 300² = 450 J (1)\n• KE after = ½ × 2.01 × 1.49² = 2.23 J (1)\n• KE lost = 450 − 2.23 = 447.8 J ≈ 448 J — the collision is highly inelastic (1)` },
      { q: 'Explain, using Newton\'s laws, why a seatbelt reduces injury in a car crash.', marks: 3, markScheme: `• In a crash, the occupant\'s momentum must change to zero (from mv to 0) (1)\n• The seatbelt increases the time over which the momentum changes (compared to hitting the dashboard) (1)\n• By F = Δp/Δt, a longer time means a smaller force on the occupant, reducing injury (1)` },
      { q: 'A projectile is launched at 40 m s⁻¹ at 30° to the horizontal from ground level. Calculate the range. (g = 9.81 m s⁻²)', marks: 4, markScheme: `• Vertical component: 40 sin 30° = 20 m s⁻¹; horizontal component: 40 cos 30° = 34.6 m s⁻¹ (1)\n• Time to highest point: t = 20/9.81 = 2.04 s; total time = 4.08 s (1)\n• Range = 34.6 × 4.08 (1)\n• Range = 141 m (1)` },
      { q: 'State the difference between elastic and inelastic collisions.', marks: 2, markScheme: `• In an elastic collision, both momentum and kinetic energy are conserved (1)\n• In an inelastic collision, momentum is conserved but kinetic energy is not — some KE is converted to other forms (heat, sound, deformation) (1)` },
      { q: 'A 60 kg person stands on bathroom scales in a lift. Calculate the reading on the scales when the lift accelerates upward at 2 m s⁻². (g = 9.81 m s⁻²)', marks: 3, markScheme: `• The scales read the normal contact force R (1)\n• Applying Newton\'s second law: R − mg = ma, so R = m(g + a) = 60(9.81 + 2) (1)\n• R = 708.6 N ≈ 709 N (equivalent to an apparent mass of ~72 kg) (1)` },
      { q: 'Explain the concept of work done by a force and state the condition under which no work is done even though a force is applied.', marks: 2, markScheme: `• Work done is the product of force and the distance moved in the direction of the force: W = Fs cos θ (1)\n• No work is done when the force is perpendicular to the direction of motion (cos 90° = 0) — e.g. centripetal force in circular motion (1)` },
      { q: 'A 500 kg roller coaster car starts from rest at the top of a 25 m hill. Calculate its speed at the bottom, assuming no friction.', marks: 2, markScheme: `• mgh = ½mv², so v = √(2gh) = √(2 × 9.81 × 25) (1)\n• v = 22.1 m s⁻¹ (1)` },
      { q: 'Describe an experiment to verify the conservation of momentum using two trolleys and a motion sensor.', marks: 4, markScheme: `• Set up two trolleys on a frictionless (or near-frictionless) track with motion sensors/light gates to measure velocities before and after collision (1)\n• Measure the mass of each trolley using a balance (1)\n• Record the velocity of each trolley before and after the collision; calculate total momentum before and after (1)\n• Compare the total momentum before and after — they should be equal within experimental uncertainty, verifying conservation of momentum (1)` },
      { q: 'A car of mass 1200 kg is travelling at 15 m s⁻¹ and brakes to a stop. All the kinetic energy is converted to thermal energy in the brakes. Calculate the thermal energy generated.', marks: 2, markScheme: `• KE = ½mv² = ½ × 1200 × 15² (1)\n• KE = 135 000 J = 135 kJ (1)` },
      { q: 'A rocket in space ejects 100 kg of exhaust gas per second at a velocity of 2000 m s⁻¹ relative to the rocket. Calculate the thrust.', marks: 2, markScheme: `• Thrust = rate of change of momentum = (Δm/Δt) × v = 100 × 2000 (1)\n• Thrust = 200 000 N = 200 kN (1)` },
      { q: 'Explain how the force-time graph for a collision relates to impulse and the change in momentum.', marks: 3, markScheme: `• The area under a force-time graph equals the impulse (FΔt) (1)\n• Impulse equals the change in momentum of the object (Δp = FΔt) (1)\n• A broader, lower peak means the same impulse is delivered over a longer time, resulting in a smaller maximum force — this is the principle behind crumple zones (1)` },
      { q: 'A 0.5 kg ball is thrown horizontally at 10 m s⁻¹ from the top of a 20 m building. Calculate the speed at which it hits the ground. (g = 9.81 m s⁻²)', marks: 3, markScheme: `• Vertical velocity: vy = √(2gh) = √(2 × 9.81 × 20) = 19.8 m s⁻¹ (1)\n• Horizontal velocity remains 10 m s⁻¹ (1)\n• Resultant speed = √(10² + 19.8²) = √(492) = 22.2 m s⁻¹ (1)` },
      { q: 'A 75 kg athlete runs at 8 m s⁻¹ and stops in 0.4 s when catching a ball. Calculate the average force on the athlete.', marks: 2, markScheme: `• F = Δp/Δt = (75 × 8) / 0.4 (1)\n• F = 1500 N (1)` },
      { q: 'Explain why a heavy lorry causes more damage in a collision than a car travelling at the same speed.', marks: 2, markScheme: `• The lorry has a greater mass and therefore greater momentum (p = mv) at the same speed (1)\n• A greater change in momentum requires either a greater force or a longer time to stop — the greater force causes more damage (1)` },
      { q: 'A 2000 kg lorry travelling at 20 m s⁻¹ collides head-on with a 1000 kg car travelling at 30 m s⁻¹ in the opposite direction. They stick together. Calculate their velocity after the collision.', marks: 3, markScheme: `• Taking the lorry\'s direction as positive: total momentum = (2000 × 20) + (1000 × −30) = 40000 − 30000 = 10000 kg m s⁻¹ (1)\n• (2000 + 1000) × v = 10000 (1)\n• v = 10000 / 3000 = 3.3 m s⁻¹ in the lorry\'s original direction (1)` },
      { q: 'Explain the principle behind crumple zones in cars, using the concepts of force, impulse, and momentum.', marks: 3, markScheme: `• In a collision, the car\'s momentum must change to zero — the impulse (FΔt = Δp) is fixed by the initial momentum (1)\n• Crumple zones deform on impact, increasing the time Δt over which the momentum changes (1)\n• Since FΔt is constant, increasing Δt decreases the average force F on the occupants, reducing injury (1)` },
      { q: 'A pendulum bob of mass 0.3 kg is released from a height of 0.2 m above its lowest point. Calculate its speed at the lowest point. (g = 9.81 m s⁻²)', marks: 2, markScheme: `• Using conservation of energy: mgh = ½mv², v = √(2 × 9.81 × 0.2) (1)\n• v = 1.98 m s⁻¹ ≈ 2.0 m s⁻¹ (1)` },
      { q: 'A horizontal force F acts on a block of mass m on a rough surface with coefficient of friction μ. Derive an expression for the acceleration.', marks: 3, markScheme: `• Friction force = μmg (1)\n• Resultant force = F − μmg (1)\n• By Newton\'s second law: a = (F − μmg) / m = F/m − μg (1)` },
      { q: 'Explain why objects of different masses fall at the same rate in a vacuum.', marks: 2, markScheme: `• In a vacuum there is no air resistance; the only force is gravity: F = mg (1)\n• By Newton\'s second law: a = F/m = mg/m = g — the mass cancels, so all objects accelerate at the same rate regardless of mass (1)` },
      { q: 'Calculate the power required for a 1200 kg car to travel at a constant 30 m s⁻¹ up a hill inclined at 5° to the horizontal. Assume no friction.', marks: 3, markScheme: `• The component of weight along the slope = mg sin 5° = 1200 × 9.81 × sin 5° = 1026 N (1)\n• At constant speed, the driving force equals this component: F = 1026 N (1)\n• P = Fv = 1026 × 30 = 30 780 W ≈ 31 kW (1)` },
      { q: 'A projectile is launched at 60° to the horizontal at 25 m s⁻¹. Calculate the time of flight and maximum height. (g = 9.81 m s⁻²)', marks: 4, markScheme: `• Vertical component: 25 sin 60° = 21.65 m s⁻¹ (1)\n• Time to highest point: t = 21.65 / 9.81 = 2.21 s; total time of flight = 4.42 s (1)\n• Maximum height: using v² = u² − 2gs: s = 21.65² / (2 × 9.81) (1)\n• s = 23.9 m (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── M4 */
  'M4': {
    name: 'Electrons, Waves and Photons',
    questions: [
      { q: 'Define electric current.', marks: 1, markScheme: `• Electric current is the rate of flow of charge: I = Q/t (1)` },
      { q: 'Define potential difference.', marks: 1, markScheme: `• Potential difference is the work done (energy transferred) per unit charge between two points: V = W/Q (1)` },
      { q: 'State Ohm\'s law.', marks: 1, markScheme: `• The current through a conductor is directly proportional to the potential difference across it, provided the temperature remains constant (for an ohmic conductor) (1)` },
      { q: 'Define resistance and state its unit.', marks: 2, markScheme: `• Resistance is the ratio of potential difference to current: R = V/I (1)\n• Unit: ohm (Ω) (1)` },
      { q: 'A current of 3.0 A flows through a component for 2 minutes. Calculate the charge that flows.', marks: 2, markScheme: `• Q = It = 3.0 × 120 (1)\n• Q = 360 C (1)` },
      { q: 'A wire has resistivity 1.7 × 10⁻⁸ Ω m, length 2.0 m, and cross-sectional area 1.0 × 10⁻⁶ m². Calculate its resistance.', marks: 2, markScheme: `• R = ρL/A = (1.7 × 10⁻⁸ × 2.0) / (1.0 × 10⁻⁶) (1)\n• R = 0.034 Ω (1)` },
      { q: 'State Kirchhoff\'s first law and explain what conservation principle it is based on.', marks: 2, markScheme: `• The sum of currents entering a junction equals the sum of currents leaving the junction (1)\n• This is based on the conservation of charge (1)` },
      { q: 'State Kirchhoff\'s second law and explain what conservation principle it is based on.', marks: 2, markScheme: `• The sum of EMFs around any closed loop in a circuit equals the sum of the potential differences in that loop (1)\n• This is based on the conservation of energy (1)` },
      { q: 'Define EMF and explain how it differs from potential difference.', marks: 2, markScheme: `• EMF is the total energy transferred per unit charge by the source (1)\n• PD is the energy transferred per unit charge between two points in the external circuit; EMF includes the energy lost across the internal resistance (1)` },
      { q: 'A battery of EMF 9.0 V and internal resistance 0.5 Ω is connected to a 4.0 Ω resistor. Calculate the current and the terminal PD.', marks: 3, markScheme: `• I = EMF / (R + r) = 9.0 / (4.0 + 0.5) = 2.0 A (1)\n• Terminal PD = EMF − Ir = 9.0 − (2.0 × 0.5) = 8.0 V (1)\n• Or V = IR = 2.0 × 4.0 = 8.0 V (1)` },
      { q: 'Three resistors of 2 Ω, 3 Ω, and 6 Ω are connected in parallel. Calculate the total resistance.', marks: 2, markScheme: `• 1/R = 1/2 + 1/3 + 1/6 = 3/6 + 2/6 + 1/6 = 6/6 = 1 (1)\n• R = 1.0 Ω (1)` },
      { q: 'Explain how a potential divider works and give its output voltage equation.', marks: 3, markScheme: `• Two resistors R₁ and R₂ are connected in series across a supply voltage Vₛ (1)\n• The output voltage is taken across one resistor (1)\n• V₂ = Vₛ × R₂ / (R₁ + R₂) (1)` },
      { q: 'In a potential divider, R₁ = 2 kΩ and R₂ is a thermistor with resistance 8 kΩ at room temperature. The supply is 10 V. Calculate the voltage across the thermistor.', marks: 2, markScheme: `• V₂ = 10 × 8000 / (2000 + 8000) (1)\n• V₂ = 8.0 V (1)` },
      { q: 'Define wavelength and frequency of a wave.', marks: 2, markScheme: `• Wavelength: the minimum distance between two points oscillating in phase (e.g. crest to crest) (1)\n• Frequency: the number of complete oscillations per unit time, measured in hertz (Hz) (1)` },
      { q: 'State the equation relating wave speed, frequency, and wavelength.', marks: 1, markScheme: `• v = fλ (1)` },
      { q: 'Describe the differences between transverse and longitudinal waves. Give one example of each.', marks: 3, markScheme: `• Transverse: oscillations are perpendicular to the direction of energy transfer — e.g. light, water waves (1)\n• Longitudinal: oscillations are parallel to the direction of energy transfer — e.g. sound waves (1)\n• Transverse waves can be polarised; longitudinal waves cannot (1)` },
      { q: 'State the conditions needed for two waves to produce a stable interference pattern.', marks: 2, markScheme: `• The waves must be coherent — same frequency and a constant phase difference (1)\n• They must overlap in the same region of space (and ideally have similar amplitudes for visible fringes) (1)` },
      { q: 'Explain the difference between constructive and destructive interference.', marks: 2, markScheme: `• Constructive interference occurs when waves arrive in phase (path difference = nλ) — amplitudes add to give a larger resultant (1)\n• Destructive interference occurs when waves arrive in antiphase (path difference = (n+½)λ) — amplitudes cancel to give zero or reduced resultant (1)` },
      { q: 'Describe the formation of a stationary wave on a string fixed at both ends.', marks: 3, markScheme: `• A progressive wave travels along the string and reflects at the fixed end (1)\n• The incident and reflected waves (same frequency, amplitude, travelling in opposite directions) superpose (1)\n• Points of zero displacement (nodes) and maximum displacement (antinodes) form at fixed positions — energy is not transferred along the string (1)` },
      { q: 'A diffraction grating has 600 lines per mm. Calculate the slit spacing and the angle of the second-order maximum for light of wavelength 550 nm.', marks: 3, markScheme: `• d = 1/600000 = 1.67 × 10⁻⁶ m (1)\n• d sin θ = nλ: sin θ = 2 × 550 × 10⁻⁹ / 1.67 × 10⁻⁶ = 0.659 (1)\n• θ = sin⁻¹(0.659) = 41.2° (1)` },
      { q: 'State Snell\'s law of refraction.', marks: 1, markScheme: `• n₁ sin θ₁ = n₂ sin θ₂ (where n is the refractive index and θ is the angle to the normal) (1)` },
      { q: 'Light travels from glass (n = 1.5) into air (n = 1.0). Calculate the critical angle.', marks: 2, markScheme: `• sin c = n₂/n₁ = 1.0/1.5 = 0.667 (1)\n• c = sin⁻¹(0.667) = 41.8° (1)` },
      { q: 'Explain the photoelectric effect and state the key observations that support the particle model of light.', marks: 4, markScheme: `• When light above a threshold frequency strikes a metal surface, electrons are emitted (1)\n• Below the threshold frequency, no electrons are emitted regardless of intensity — this cannot be explained by the wave model (1)\n• The maximum kinetic energy of emitted electrons depends on the frequency of the light, not its intensity (1)\n• Emission is instantaneous — there is no time delay, supporting the idea that energy is delivered in discrete packets (photons) (1)` },
      { q: 'State the photoelectric equation and define each term.', marks: 2, markScheme: `• hf = φ + KE_max (or E_photon = work function + maximum kinetic energy) (1)\n• h = Planck\'s constant; f = frequency of incident light; φ = work function (minimum energy to release an electron); KE_max = maximum kinetic energy of emitted electrons (1)` },
      { q: 'The work function of a metal is 4.5 eV. Calculate the threshold frequency. (h = 6.63 × 10⁻³⁴ J s)', marks: 2, markScheme: `• φ = hf₀: f₀ = φ/h = (4.5 × 1.6 × 10⁻¹⁹) / (6.63 × 10⁻³⁴) (1)\n• f₀ = 1.09 × 10¹⁵ Hz (1)` },
      { q: 'Calculate the energy of a photon of wavelength 450 nm. (h = 6.63 × 10⁻³⁴ J s, c = 3 × 10⁸ m s⁻¹)', marks: 2, markScheme: `• E = hc/λ = (6.63 × 10⁻³⁴ × 3 × 10⁸) / (450 × 10⁻⁹) (1)\n• E = 4.42 × 10⁻¹⁹ J = 2.76 eV (1)` },
      { q: 'Explain what is meant by energy levels in an atom and how they relate to line spectra.', marks: 3, markScheme: `• Electrons in an atom can only occupy discrete energy levels (1)\n• When an electron transitions from a higher to a lower energy level, it emits a photon with energy equal to the difference between the levels: E = hf (1)\n• Each transition produces a specific frequency/wavelength of light, resulting in a line emission spectrum unique to that element (1)` },
      { q: 'An electron is accelerated through a PD of 200 V. Calculate its de Broglie wavelength. (m = 9.11 × 10⁻³¹ kg, h = 6.63 × 10⁻³⁴ J s, e = 1.6 × 10⁻¹⁹ C)', marks: 3, markScheme: `• KE = eV = 1.6 × 10⁻¹⁹ × 200 = 3.2 × 10⁻¹⁷ J (1)\n• v = √(2KE/m) = √(2 × 3.2 × 10⁻¹⁷ / 9.11 × 10⁻³¹) = 8.38 × 10⁶ m s⁻¹ (1)\n• λ = h/mv = 6.63 × 10⁻³⁴ / (9.11 × 10⁻³¹ × 8.38 × 10⁶) = 8.67 × 10⁻¹¹ m (1)` },
      { q: 'Describe the I-V characteristic of a filament lamp and explain why it has this shape.', marks: 3, markScheme: `• The graph curves upward from the origin — current increases less rapidly as PD increases (1)\n• As current increases, the filament temperature rises, which increases the resistance of the wire (1)\n• The resistance increases because ions in the metal lattice vibrate more at higher temperatures, impeding electron flow (1)` },
      { q: 'Describe the I-V characteristic of a diode.', marks: 2, markScheme: `• In forward bias above the threshold PD (~0.6 V for silicon), current increases rapidly (1)\n• In reverse bias, virtually no current flows (until breakdown voltage) (1)` },
      { q: 'Explain why increasing the intensity of light does not increase the maximum kinetic energy of photoelectrons.', marks: 3, markScheme: `• Each photon interacts with one electron in a one-to-one process (1)\n• The maximum KE depends on the energy of each photon (hf) minus the work function — it is independent of the number of photons (1)\n• Increasing intensity increases the number of photons per second (and hence the rate of electron emission / photocurrent), not the energy per photon (1)` },
      { q: 'Two coherent light sources are separated by 0.25 mm. The interference pattern is observed on a screen 1.5 m away. The fringe spacing is 3.6 mm. Calculate the wavelength of the light.', marks: 2, markScheme: `• λ = ax/D = (0.25 × 10⁻³ × 3.6 × 10⁻³) / 1.5 (1)\n• λ = 6.0 × 10⁻⁷ m = 600 nm (1)` },
      { q: 'Explain why a single slit must be used before a double slit in Young\'s double-slit experiment.', marks: 2, markScheme: `• The single slit acts as a point source, ensuring the light arriving at both slits is coherent (same frequency and constant phase relationship) (1)\n• Without the single slit, the light from an extended source would not be coherent at the double slit and no stable interference pattern would be observed (1)` },
      { q: 'A battery of EMF 6.0 V and internal resistance 1.0 Ω is connected to two 4.0 Ω resistors in parallel. Calculate the current from the battery and the PD across the parallel combination.', marks: 4, markScheme: `• Parallel resistance: 1/R = 1/4 + 1/4 = 2/4, R = 2.0 Ω (1)\n• Total circuit resistance = 2.0 + 1.0 = 3.0 Ω (1)\n• Current from battery: I = 6.0 / 3.0 = 2.0 A (1)\n• PD across parallel combination: V = IR = 2.0 × 2.0 = 4.0 V (or V = 6.0 − 2.0 × 1.0 = 4.0 V) (1)` },
      { q: 'State the electromagnetic spectrum in order of increasing wavelength.', marks: 2, markScheme: `• Gamma rays, X-rays, ultraviolet, visible light, infrared, microwaves, radio waves (1)\n• All travel at the speed of light in a vacuum (3 × 10⁸ m s⁻¹) and are transverse electromagnetic waves (1)` },
      { q: 'Explain what is meant by polarisation and state what it tells us about the nature of light.', marks: 2, markScheme: `• Polarisation is the restriction of oscillations to a single plane perpendicular to the direction of energy transfer (1)\n• Only transverse waves can be polarised — the fact that light can be polarised proves it is a transverse wave (1)` },
      { q: 'A string of length 1.2 m is fixed at both ends and vibrates in its third harmonic. Calculate the wavelength and, given that the wave speed is 240 m s⁻¹, calculate the frequency.', marks: 3, markScheme: `• Third harmonic: L = 3λ/2, so λ = 2L/3 = 2 × 1.2 / 3 = 0.8 m (1)\n• f = v/λ = 240 / 0.8 (1)\n• f = 300 Hz (1)` },
      { q: 'Calculate the maximum number of orders visible when light of wavelength 650 nm passes through a diffraction grating with slit spacing 2.0 × 10⁻⁶ m.', marks: 2, markScheme: `• For the maximum order: sin θ ≤ 1, so n ≤ d/λ = 2.0 × 10⁻⁶ / 650 × 10⁻⁹ = 3.08 (1)\n• Maximum whole order n = 3 (so orders 0, ±1, ±2, ±3 are visible) (1)` },
      { q: 'Explain why a diffraction grating produces sharper maxima than a double slit.', marks: 2, markScheme: `• A grating has many slits (thousands), so many waves interfere simultaneously (1)\n• The condition for constructive interference is very precisely defined — even a small deviation from the exact angle causes destructive interference from the large number of sources, producing very narrow, bright maxima (1)` },
      { q: 'Describe the de Broglie hypothesis and explain how electron diffraction provides evidence for it.', marks: 3, markScheme: `• De Broglie proposed that all matter has an associated wavelength given by λ = h/p = h/mv (1)\n• When electrons are fired through a thin crystal or graphite, they produce a diffraction pattern of concentric rings (1)\n• Diffraction is a wave phenomenon — the pattern can only be explained if electrons behave as waves, with a wavelength consistent with the de Broglie equation (1)` },
      { q: 'Explain how a light-dependent resistor (LDR) can be used in a potential divider circuit to produce a voltage that varies with light intensity.', marks: 3, markScheme: `• An LDR is connected in series with a fixed resistor across a power supply (1)\n• As light intensity increases, the resistance of the LDR decreases (1)\n• If the output is taken across the fixed resistor: V_out = V_s × R_fixed / (R_LDR + R_fixed), which increases with light intensity (or vice versa if taken across the LDR) (1)` },
      { q: 'Calculate the power dissipated in a 10 Ω resistor carrying a current of 2.5 A.', marks: 2, markScheme: `• P = I²R = 2.5² × 10 (1)\n• P = 62.5 W (1)` },
      { q: 'A resistor has a resistance of 47 Ω at 20°C. Explain qualitatively how its resistance changes with increasing temperature if it is made of (i) a metal and (ii) a semiconductor.', marks: 3, markScheme: `• Metal: resistance increases with temperature — increased lattice vibrations scatter conduction electrons more frequently (1)\n• Semiconductor (e.g. thermistor with negative temperature coefficient): resistance decreases with temperature (1)\n• In a semiconductor, increasing temperature provides more energy to release charge carriers from bonds, greatly increasing the number of free electrons, which outweighs increased scattering (1)` },
      { q: 'Explain the significance of the stopping potential in a photoelectric effect experiment.', marks: 3, markScheme: `• The stopping potential Vs is the minimum PD needed to reduce the photocurrent to zero (1)\n• It provides a measure of the maximum kinetic energy of the emitted photoelectrons: KE_max = eVs (1)\n• By measuring Vs for different frequencies, a graph of Vs against f gives a straight line with gradient h/e and x-intercept at the threshold frequency (1)` },
      { q: 'A 12 V battery with internal resistance 2 Ω is short-circuited. Calculate the current and explain why this is dangerous.', marks: 3, markScheme: `• I = EMF/r = 12/2 = 6 A (1)\n• Power dissipated in internal resistance: P = I²r = 36 × 2 = 72 W (1)\n• This large current and power dissipation generates significant heat within the battery, which could cause overheating, damage to the battery, or even a fire/explosion (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── M5 */
  'M5': {
    name: 'Newtonian World and Astrophysics',
    questions: [
      { q: 'Define internal energy.', marks: 2, markScheme: `• The sum of the randomly distributed kinetic energies and potential energies of all the particles in a system (1)\n• Kinetic energy relates to temperature; potential energy relates to intermolecular forces (1)` },
      { q: 'State the equation for specific heat capacity and define each term.', marks: 2, markScheme: `• Q = mcΔθ where Q = energy transferred, m = mass, c = specific heat capacity, Δθ = temperature change (1)\n• c is the energy required to raise the temperature of 1 kg of the substance by 1 K (1)` },
      { q: 'Calculate the energy needed to heat 0.5 kg of water from 20°C to 100°C. (c = 4200 J kg⁻¹ K⁻¹)', marks: 2, markScheme: `• Q = mcΔθ = 0.5 × 4200 × 80 (1)\n• Q = 168 000 J = 168 kJ (1)` },
      { q: 'Explain why temperature remains constant during a change of state.', marks: 2, markScheme: `• Energy supplied is used to break (or form) intermolecular bonds — it changes the potential energy, not the kinetic energy (1)\n• Since temperature is related to the average kinetic energy of the particles, the temperature remains constant during the phase change (1)` },
      { q: 'State the ideal gas equation and define each term.', marks: 2, markScheme: `• pV = nRT where p = pressure, V = volume, n = number of moles, R = molar gas constant (8.31 J mol⁻¹ K⁻¹), T = absolute temperature in kelvin (1)\n• Alternatively pV = NkT where N = number of molecules and k = Boltzmann constant (1)` },
      { q: 'An ideal gas at 300 K and 100 kPa occupies 0.02 m³. Calculate the number of moles.', marks: 2, markScheme: `• n = pV/RT = (100 × 10³ × 0.02) / (8.31 × 300) (1)\n• n = 0.802 mol ≈ 0.80 mol (1)` },
      { q: 'State the assumptions of the kinetic theory of ideal gases.', marks: 3, markScheme: `• Gas consists of a large number of identical molecules in random motion; the volume of the molecules is negligible compared to the volume of the container (1)\n• Collisions between molecules and with the walls are perfectly elastic; the time of collisions is negligible compared to the time between collisions (1)\n• There are no intermolecular forces except during collisions (1)` },
      { q: 'State the equation for the mean kinetic energy of a gas molecule and calculate it at 400 K.', marks: 2, markScheme: `• ½m⟨c²⟩ = (3/2)kT = 1.5 × 1.38 × 10⁻²³ × 400 (1)\n• = 8.28 × 10⁻²¹ J (1)` },
      { q: 'Define angular velocity and state its unit.', marks: 2, markScheme: `• Angular velocity ω is the rate of change of angle: ω = Δθ/Δt = 2πf = 2π/T (1)\n• Unit: rad s⁻¹ (1)` },
      { q: 'A mass moves in a circle of radius 0.5 m at 3 rev s⁻¹. Calculate the angular velocity and the centripetal acceleration.', marks: 3, markScheme: `• ω = 2πf = 2π × 3 = 18.85 rad s⁻¹ (1)\n• a = ω²r = 18.85² × 0.5 (1)\n• a = 177.7 m s⁻² ≈ 178 m s⁻² (1)` },
      { q: 'Explain why a centripetal force is needed for circular motion but does no work.', marks: 2, markScheme: `• A centripetal force is needed because the direction of velocity is constantly changing, even if the speed is constant — by Newton\'s first law, a force must act to change the direction (1)\n• The force does no work because it is always perpendicular to the velocity/displacement — W = Fs cos 90° = 0 (1)` },
      { q: 'State the conditions for simple harmonic motion (SHM).', marks: 2, markScheme: `• The acceleration is proportional to the displacement from the equilibrium position (1)\n• The acceleration is always directed towards the equilibrium position: a = −ω²x (1)` },
      { q: 'A mass oscillates in SHM with amplitude 0.05 m and frequency 4 Hz. Calculate the maximum velocity.', marks: 2, markScheme: `• v_max = ωA = 2πfA = 2π × 4 × 0.05 (1)\n• v_max = 1.26 m s⁻¹ (1)` },
      { q: 'A mass on a spring (k = 20 N m⁻¹, m = 0.5 kg) oscillates. Calculate the period and frequency.', marks: 2, markScheme: `• T = 2π√(m/k) = 2π√(0.5/20) = 2π × 0.158 = 0.993 s (1)\n• f = 1/T = 1.007 Hz ≈ 1.0 Hz (1)` },
      { q: 'Describe and compare light, heavy, and critical damping.', marks: 3, markScheme: `• Light damping: amplitude decreases gradually; the system oscillates many times before stopping (e.g. pendulum in air) (1)\n• Heavy (over) damping: no oscillations; the system returns to equilibrium very slowly (e.g. door closer with high resistance) (1)\n• Critical damping: no oscillations; the system returns to equilibrium in the shortest possible time (e.g. car shock absorbers) (1)` },
      { q: 'Explain the phenomenon of resonance and give one example where it is useful and one where it is harmful.', marks: 3, markScheme: `• Resonance occurs when the driving frequency matches the natural frequency of a system, causing the amplitude of oscillation to reach a maximum (1)\n• Useful: tuning a radio — the circuit resonates at the frequency of the desired station (1)\n• Harmful: the Tacoma Narrows Bridge collapse / vibrations in machinery — resonance can cause structural failure (1)` },
      { q: 'State Newton\'s law of gravitation and give the equation.', marks: 2, markScheme: `• Every particle attracts every other particle with a force proportional to the product of their masses and inversely proportional to the square of the distance between them (1)\n• F = GMm/r² where G = 6.67 × 10⁻¹¹ N m² kg⁻² (1)` },
      { q: 'Define gravitational field strength and state whether it is a scalar or vector.', marks: 2, markScheme: `• Gravitational field strength g is the force per unit mass at a point in a gravitational field: g = F/m (1)\n• It is a vector quantity — it points towards the centre of the mass producing the field (1)` },
      { q: 'Calculate the gravitational field strength at the surface of Mars (mass 6.4 × 10²³ kg, radius 3.4 × 10⁶ m). (G = 6.67 × 10⁻¹¹ N m² kg⁻²)', marks: 2, markScheme: `• g = GM/r² = (6.67 × 10⁻¹¹ × 6.4 × 10²³) / (3.4 × 10⁶)² (1)\n• g = 3.69 m s⁻² ≈ 3.7 m s⁻² (1)` },
      { q: 'Define gravitational potential and explain why it is always negative.', marks: 2, markScheme: `• Gravitational potential at a point is the work done per unit mass in bringing a test mass from infinity to that point: V = −GM/r (1)\n• It is always negative because gravity is attractive — work must be done against gravity to move a mass from the point to infinity (where V = 0) (1)` },
      { q: 'Derive an expression for the orbital speed of a satellite at height h above a planet of mass M and radius R.', marks: 3, markScheme: `• Gravitational force provides centripetal force: GMm/(R+h)² = mv²/(R+h) (1)\n• Simplifying: v² = GM/(R+h) (1)\n• v = √(GM/(R+h)) (1)` },
      { q: 'State Kepler\'s third law and show how it follows from Newton\'s law of gravitation.', marks: 3, markScheme: `• T² ∝ r³ for objects orbiting the same central body (1)\n• From GMm/r² = mω²r and ω = 2π/T: GM/r² = (4π²/T²)r (1)\n• Rearranging: T² = (4π²/GM)r³ — confirming T² ∝ r³ with constant 4π²/GM (1)` },
      { q: 'State Wien\'s displacement law and use it to calculate the surface temperature of a star with peak wavelength 350 nm.', marks: 2, markScheme: `• Wien\'s law: λ_max × T = 2.9 × 10⁻³ m K (1)\n• T = 2.9 × 10⁻³ / 350 × 10⁻⁹ = 8286 K ≈ 8300 K (1)` },
      { q: 'State the Stefan-Boltzmann law and calculate the luminosity of a star with radius 7 × 10⁸ m and surface temperature 6000 K. (σ = 5.67 × 10⁻⁸ W m⁻² K⁻⁴)', marks: 3, markScheme: `• L = 4πr²σT⁴ (1)\n• L = 4π × (7 × 10⁸)² × 5.67 × 10⁻⁸ × 6000⁴ (1)\n• L = 4π × 4.9 × 10¹⁷ × 5.67 × 10⁻⁸ × 1.296 × 10¹⁵ = 4.53 × 10²⁶ W (1)` },
      { q: 'Define Hubble\'s constant and explain how it is used to estimate the age of the universe.', marks: 3, markScheme: `• Hubble\'s constant H₀ relates a galaxy\'s recessional velocity to its distance: v = H₀d (1)\n• If the expansion has been constant, the time since the Big Bang is approximately t = 1/H₀ (1)\n• Using H₀ ≈ 70 km s⁻¹ Mpc⁻¹, the estimated age is about 14 billion years (1)` },
      { q: 'Explain what is meant by cosmological redshift and how it differs from Doppler redshift.', marks: 3, markScheme: `• Cosmological redshift: the stretching of light wavelengths due to the expansion of space itself — the space between us and the galaxy has expanded while the light was in transit (1)\n• Doppler redshift: a shift in frequency/wavelength due to the relative motion of source and observer through space (1)\n• Cosmological redshift is fundamentally different — it is not caused by the galaxy moving through space but by space itself expanding, stretching the wavelength of light (1)` },
      { q: 'Describe the life cycle of a star with a mass similar to the Sun.', marks: 4, markScheme: `• Nebula → protostar: a cloud of gas and dust collapses under gravity, heating up (1)\n• Main sequence: hydrogen fusion in the core provides outward radiation pressure to balance gravity — the star is stable for billions of years (1)\n• Red giant: hydrogen in the core is exhausted; the core contracts and heats, outer layers expand and cool; helium fusion begins (1)\n• Planetary nebula + white dwarf: outer layers are ejected; the remaining core (no fusion) slowly cools as a white dwarf (1)` },
      { q: 'A gas is heated at constant volume from 300 K to 450 K. If the initial pressure is 120 kPa, calculate the final pressure.', marks: 2, markScheme: `• At constant volume: P₁/T₁ = P₂/T₂, so P₂ = 120 × 450/300 (1)\n• P₂ = 180 kPa (1)` },
      { q: 'A simple pendulum has a period of 2.0 s. Calculate its length. (g = 9.81 m s⁻²)', marks: 2, markScheme: `• T = 2π√(l/g): l = gT²/4π² = 9.81 × 4 / (4π²) (1)\n• l = 0.994 m ≈ 0.99 m (1)` },
      { q: 'A Hertzsprung-Russell diagram plots luminosity against surface temperature. Describe the locations and characteristics of main sequence stars, red giants, and white dwarfs.', marks: 3, markScheme: `• Main sequence: a diagonal band from hot/luminous (top left) to cool/dim (bottom right) — stars fusing hydrogen (1)\n• Red giants/supergiants: top right — high luminosity but relatively cool surface temperature, meaning they must have very large radii (1)\n• White dwarfs: bottom left — hot surface temperature but low luminosity, meaning they must have very small radii (1)` },
      { q: 'Calculate the escape velocity from the surface of Earth. (M = 5.97 × 10²⁴ kg, R = 6.37 × 10⁶ m, G = 6.67 × 10⁻¹¹ N m² kg⁻²)', marks: 2, markScheme: `• v = √(2GM/R) = √(2 × 6.67 × 10⁻¹¹ × 5.97 × 10²⁴ / 6.37 × 10⁶) (1)\n• v = 11 200 m s⁻¹ ≈ 11.2 km s⁻¹ (1)` },
      { q: 'Explain why geostationary orbits are useful for communications satellites and state the conditions for a geostationary orbit.', marks: 3, markScheme: `• A geostationary satellite has a period of 24 hours, orbits above the equator, and orbits in the same direction as Earth\'s rotation (west to east) (1)\n• This means it appears stationary relative to a point on Earth\'s surface (1)\n• Useful for communications because ground-based satellite dishes can be fixed in one direction rather than tracking a moving satellite (1)` },
      { q: 'At what point in SHM is the potential energy maximum and the kinetic energy zero?', marks: 1, markScheme: `• At the maximum displacement (amplitude) — the object is momentarily at rest, so all energy is potential (1)` },
      { q: 'Show that the total energy of a mass-spring system undergoing SHM is E = ½kA² where A is the amplitude.', marks: 3, markScheme: `• At maximum displacement x = A, the velocity is zero so KE = 0 (1)\n• All energy is stored as elastic PE = ½kx² = ½kA² (1)\n• Since total energy is conserved (no damping), the total energy at any point equals ½kA² (1)` },
      { q: 'An astronaut weighs 700 N on Earth. Calculate their weight on the Moon (g_Moon = 1.63 m s⁻²).', marks: 2, markScheme: `• Mass = 700/9.81 = 71.4 kg (1)\n• Weight on Moon = 71.4 × 1.63 = 116 N (1)` },
      { q: 'Explain what is meant by the Big Bang theory.', marks: 2, markScheme: `• The Big Bang theory states that the universe began from an extremely hot, dense singularity approximately 13.8 billion years ago (1)\n• Since then, the universe has been expanding and cooling, as evidenced by Hubble\'s law and the cosmic microwave background radiation (1)` },
      { q: 'Describe the evidence for the expanding universe provided by the observation of galactic redshift.', marks: 3, markScheme: `• Spectral lines from distant galaxies are shifted towards longer wavelengths (redshifted) compared to laboratory spectra (1)\n• The redshift increases with distance — more distant galaxies show greater redshift (Hubble\'s law) (1)\n• This indicates that galaxies are receding from us, with more distant galaxies receding faster — consistent with the expansion of space itself (1)` },
      { q: 'A resonance tube (closed at one end) has a first harmonic at 0.25 m. Calculate the frequency of the first harmonic. (Speed of sound = 340 m s⁻¹)', marks: 2, markScheme: `• For a tube closed at one end, first harmonic: L = λ/4, so λ = 4 × 0.25 = 1.0 m (1)\n• f = v/λ = 340/1.0 = 340 Hz (1)` },
      { q: 'An ice cube of mass 0.05 kg at 0°C is added to 0.3 kg of water at 25°C. Calculate the final temperature. (L_f = 3.34 × 10⁵ J kg⁻¹, c_water = 4200 J kg⁻¹ K⁻¹)', marks: 4, markScheme: `• Energy to melt ice: Q₁ = mL = 0.05 × 3.34 × 10⁵ = 16 700 J (1)\n• Energy to heat melted ice from 0°C to T: Q₂ = 0.05 × 4200 × T (1)\n• Energy lost by warm water: Q₃ = 0.3 × 4200 × (25 − T) (1)\n• Q₁ + Q₂ = Q₃: 16700 + 210T = 31500 − 1260T; 1470T = 14800; T = 10.1°C (1)` },
      { q: 'A 0.1 mol sample of ideal gas is compressed isothermally at 350 K from 2.0 × 10⁻³ m³ to 0.5 × 10⁻³ m³. Calculate the final pressure.', marks: 2, markScheme: `• At constant temperature: p₁V₁ = p₂V₂. First find p₁ = nRT/V₁ = (0.1 × 8.31 × 350) / 2.0 × 10⁻³ = 145 425 Pa (1)\n• p₂ = p₁V₁/V₂ = 145 425 × 2.0 × 10⁻³ / 0.5 × 10⁻³ = 581 700 Pa ≈ 582 kPa (1)` },
      { q: 'Explain why massive stars have shorter main-sequence lifetimes than less massive stars.', marks: 2, markScheme: `• Although massive stars have more hydrogen fuel, their luminosity (and hence rate of fuel consumption) is much greater — luminosity scales roughly as M³·⁵ (1)\n• They burn through their fuel much faster, resulting in main-sequence lifetimes of millions rather than billions of years (1)` },
      { q: 'Explain the difference between the gravitational field strength g and the gravitational potential V at a point in a gravitational field.', marks: 3, markScheme: `• g is the force per unit mass: g = F/m = GM/r² (a vector, pointing towards the mass) (1)\n• V is the work done per unit mass to bring a test mass from infinity: V = −GM/r (a scalar, always negative) (1)\n• They are related: g = −dV/dr — the field strength equals the negative gradient of the potential (1)` },
      { q: 'A galaxy has a redshift z = 0.03. Estimate its distance from Earth using H₀ = 70 km s⁻¹ Mpc⁻¹.', marks: 3, markScheme: `• Recessional velocity: v = zc = 0.03 × 3 × 10⁵ km s⁻¹ = 9000 km s⁻¹ (1)\n• d = v/H₀ = 9000/70 (1)\n• d = 128.6 Mpc ≈ 129 Mpc (1)` },
      { q: 'Derive an expression for the total translational kinetic energy of N molecules of an ideal gas at temperature T.', marks: 2, markScheme: `• Each molecule has mean KE = (3/2)kT (1)\n• Total KE for N molecules = (3/2)NkT = (3/2)nRT (since Nk = nR) (1)` },
      { q: 'Calculate the rms speed of oxygen molecules at 300 K. (M = 32 × 10⁻³ kg mol⁻¹, R = 8.31 J mol⁻¹ K⁻¹)', marks: 2, markScheme: `• c_rms = √(3RT/M) = √(3 × 8.31 × 300 / 32 × 10⁻³) (1)\n• c_rms = √(233 344) = 483 m s⁻¹ (1)` },
      { q: 'A satellite orbits Earth at a height of 400 km. Calculate its orbital speed and period. (M_E = 5.97 × 10²⁴ kg, R_E = 6.37 × 10⁶ m, G = 6.67 × 10⁻¹¹ N m² kg⁻²)', marks: 4, markScheme: `• Orbital radius r = 6.37 × 10⁶ + 400 × 10³ = 6.77 × 10⁶ m (1)\n• v = √(GM/r) = √(6.67 × 10⁻¹¹ × 5.97 × 10²⁴ / 6.77 × 10⁶) = 7672 m s⁻¹ ≈ 7.7 km s⁻¹ (1)\n• T = 2πr/v = 2π × 6.77 × 10⁶ / 7672 (1)\n• T = 5544 s ≈ 92.4 minutes (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── M6 */
  'M6': {
    name: 'Particles and Medical Physics',
    questions: [
      { q: 'Define capacitance and state its unit.', marks: 2, markScheme: `• Capacitance is the charge stored per unit potential difference: C = Q/V (1)\n• Unit: farad (F) (1)` },
      { q: 'A 470 μF capacitor is charged to 6.0 V. Calculate the charge stored and the energy stored.', marks: 3, markScheme: `• Q = CV = 470 × 10⁻⁶ × 6.0 = 2.82 × 10⁻³ C (1)\n• E = ½QV = ½ × 2.82 × 10⁻³ × 6.0 (1)\n• E = 8.46 × 10⁻³ J ≈ 8.5 mJ (1)` },
      { q: 'State the time constant of an RC circuit and explain its significance.', marks: 2, markScheme: `• Time constant τ = RC (1)\n• It is the time for the charge (or current or voltage) to fall to 1/e (≈ 37%) of its initial value during discharge, or to rise to (1 − 1/e) ≈ 63% of its final value during charging (1)` },
      { q: 'A 100 μF capacitor discharges through a 20 kΩ resistor. Calculate the time constant and the time for the voltage to fall to 10% of its initial value.', marks: 3, markScheme: `• τ = RC = 20 × 10³ × 100 × 10⁻⁶ = 2.0 s (1)\n• V = V₀ e^(−t/RC): 0.1 = e^(−t/2), so −t/2 = ln(0.1) = −2.303 (1)\n• t = 4.6 s (1)` },
      { q: 'State Coulomb\'s law and give its equation.', marks: 2, markScheme: `• The force between two point charges is proportional to the product of the charges and inversely proportional to the square of the distance between them (1)\n• F = kQ₁Q₂/r² where k = 1/(4πε₀) = 8.99 × 10⁹ N m² C⁻² (1)` },
      { q: 'Define electric field strength and state its unit.', marks: 2, markScheme: `• Electric field strength is the force per unit positive charge at a point: E = F/Q (1)\n• Unit: N C⁻¹ (or equivalently V m⁻¹) (1)` },
      { q: 'Calculate the electric field strength between two parallel plates separated by 5 mm with a PD of 200 V between them.', marks: 2, markScheme: `• E = V/d = 200 / 5 × 10⁻³ (1)\n• E = 40 000 V m⁻¹ = 40 kV m⁻¹ (1)` },
      { q: 'State the equation for the force on a current-carrying wire in a magnetic field and define each term.', marks: 2, markScheme: `• F = BIL sin θ where B = magnetic flux density, I = current, L = length of wire, θ = angle between wire and field (1)\n• The force is maximum when the wire is perpendicular to the field (sin 90° = 1) and zero when parallel (1)` },
      { q: 'State the equation for the force on a moving charged particle in a magnetic field.', marks: 1, markScheme: `• F = BQv sin θ where B = magnetic flux density, Q = charge, v = velocity, θ = angle between velocity and field (1)` },
      { q: 'An electron moves at 5 × 10⁶ m s⁻¹ perpendicular to a magnetic field of 0.02 T. Calculate the force and the radius of its circular path. (e = 1.6 × 10⁻¹⁹ C, m = 9.11 × 10⁻³¹ kg)', marks: 3, markScheme: `• F = BQv = 0.02 × 1.6 × 10⁻¹⁹ × 5 × 10⁶ = 1.6 × 10⁻¹⁴ N (1)\n• F = mv²/r, so r = mv/(BQ) = (9.11 × 10⁻³¹ × 5 × 10⁶) / (0.02 × 1.6 × 10⁻¹⁹) (1)\n• r = 1.42 × 10⁻³ m ≈ 1.4 mm (1)` },
      { q: 'State Faraday\'s law of electromagnetic induction.', marks: 1, markScheme: `• The induced EMF is equal to the rate of change of magnetic flux linkage: EMF = −d(NΦ)/dt (1)` },
      { q: 'State Lenz\'s law and explain its physical basis.', marks: 2, markScheme: `• The induced EMF acts in a direction to oppose the change in flux that produces it (1)\n• This is a consequence of the conservation of energy — if the induced current aided the change, energy would be created from nothing (1)` },
      { q: 'A coil of 100 turns has a flux through it that changes from 0.04 Wb to 0.01 Wb in 0.2 s. Calculate the induced EMF.', marks: 2, markScheme: `• EMF = NΔΦ/Δt = 100 × (0.04 − 0.01) / 0.2 (1)\n• EMF = 15 V (1)` },
      { q: 'Define magnetic flux and magnetic flux linkage.', marks: 2, markScheme: `• Magnetic flux Φ = BA cos θ, where B = flux density, A = area, θ = angle between B and the normal to the area; unit: weber (Wb) (1)\n• Magnetic flux linkage = NΦ where N is the number of turns on a coil; unit: Wb (or Wb turns) (1)` },
      { q: 'Define the decay constant λ and write the equation for radioactive decay.', marks: 2, markScheme: `• λ is the probability of decay per unit time for a single nucleus (1)\n• N = N₀ e^(−λt) where N is the number of undecayed nuclei at time t (or A = A₀ e^(−λt) for activity) (1)` },
      { q: 'A radioactive isotope has a half-life of 5 days. Calculate the decay constant.', marks: 2, markScheme: `• λ = ln 2 / t½ = 0.693 / (5 × 24 × 3600) (1)\n• λ = 1.60 × 10⁻⁶ s⁻¹ (1)` },
      { q: 'A sample initially contains 10⁸ radioactive nuclei with λ = 0.05 s⁻¹. Calculate the initial activity and the activity after 20 s.', marks: 3, markScheme: `• A₀ = λN₀ = 0.05 × 10⁸ = 5 × 10⁶ Bq (1)\n• A = A₀ e^(−λt) = 5 × 10⁶ × e^(−0.05 × 20) = 5 × 10⁶ × e⁻¹ (1)\n• A = 1.84 × 10⁶ Bq ≈ 1.8 MBq (1)` },
      { q: 'Describe alpha, beta-minus, and gamma radiation in terms of their nature and penetrating power.', marks: 3, markScheme: `• Alpha (α): helium nucleus (2p + 2n), charge +2e, highly ionising, stopped by paper or a few cm of air (1)\n• Beta-minus (β⁻): high-speed electron from the nucleus, charge −e, moderately ionising, stopped by a few mm of aluminium (1)\n• Gamma (γ): high-energy electromagnetic radiation, no charge, weakly ionising, reduced significantly by several cm of lead or thick concrete (1)` },
      { q: 'Explain what is meant by mass defect and binding energy.', marks: 2, markScheme: `• Mass defect is the difference between the total mass of the individual nucleons and the actual mass of the nucleus — the nucleus has less mass (1)\n• Binding energy is the energy equivalent of the mass defect (E = Δmc²) — the energy required to completely separate all nucleons in the nucleus (1)` },
      { q: 'Calculate the energy released when 1 u of mass is converted to energy. (1 u = 1.66 × 10⁻²⁷ kg, c = 3 × 10⁸ m s⁻¹)', marks: 2, markScheme: `• E = mc² = 1.66 × 10⁻²⁷ × (3 × 10⁸)² (1)\n• E = 1.49 × 10⁻¹⁰ J = 931.5 MeV (1)` },
      { q: 'Explain the difference between nuclear fission and nuclear fusion.', marks: 2, markScheme: `• Fission: a heavy nucleus splits into two lighter nuclei (plus neutrons), releasing energy — used in nuclear reactors (1)\n• Fusion: two light nuclei combine to form a heavier nucleus, releasing energy — occurs in stars (1)` },
      { q: 'In the fission reaction ²³⁵U + ¹n → ¹⁴¹Ba + ⁹²Kr + 3¹n, explain why energy is released.', marks: 2, markScheme: `• The products (Ba-141 and Kr-92) have higher binding energy per nucleon than U-235 (1)\n• The increase in total binding energy is released as kinetic energy of the products and gamma radiation (E = Δmc²) (1)` },
      { q: 'State the quark composition of a proton and a neutron. Explain how beta-minus decay is described at the quark level.', marks: 3, markScheme: `• Proton: uud (charge +2/3 +2/3 −1/3 = +1); Neutron: udd (charge +2/3 −1/3 −1/3 = 0) (1)\n• In beta-minus decay, a down quark changes to an up quark: d → u + e⁻ + ν̄ₑ (1)\n• This is mediated by the weak nuclear force through the exchange of a W⁻ boson (1)` },
      { q: 'Name the four fundamental forces and their exchange particles.', marks: 4, markScheme: `• Strong nuclear force: gluons (1)\n• Weak nuclear force: W⁺, W⁻, and Z⁰ bosons (1)\n• Electromagnetic force: virtual photons (1)\n• Gravity: graviton (hypothetical, not yet observed) (1)` },
      { q: 'State the conservation laws that must be obeyed in particle interactions.', marks: 2, markScheme: `• Conservation of: charge, baryon number, lepton number (1)\n• Conservation of energy and momentum (1)` },
      { q: 'Explain why the reaction p → n + e⁺ + νₑ cannot occur spontaneously in free space.', marks: 2, markScheme: `• The neutron has a greater mass than the proton, so this reaction would require additional energy input (violates conservation of energy for a free proton at rest) (1)\n• However, this process (inverse beta decay / beta-plus decay) can occur inside a nucleus where the binding energy difference provides the needed energy (1)` },
      { q: 'Describe how X-rays are produced for medical imaging.', marks: 3, markScheme: `• Electrons are emitted from a heated cathode and accelerated through a high PD (e.g. 30–150 kV) towards a metal target (e.g. tungsten) (1)\n• When the electrons decelerate rapidly on hitting the target, they emit X-rays (bremsstrahlung/braking radiation) with a continuous spectrum (1)\n• Characteristic X-rays are also produced when incoming electrons knock out inner-shell electrons and higher-energy electrons transition to fill the gaps (1)` },
      { q: 'Explain how a CT scanner differs from a standard X-ray image.', marks: 3, markScheme: `• A standard X-ray produces a 2D shadow image — structures overlap and depth information is lost (1)\n• A CT scanner takes X-ray images from many angles around the body (1)\n• A computer combines these into cross-sectional (tomographic) images, allowing 3D reconstruction with much better soft-tissue contrast and no overlapping of structures (1)` },
      { q: 'Explain how ultrasound is used in medical imaging. Include the role of acoustic impedance.', marks: 4, markScheme: `• High-frequency sound pulses are transmitted into the body by a transducer placed on the skin (with coupling gel to reduce reflection at the air-skin boundary) (1)\n• When the ultrasound reaches a boundary between two tissues with different acoustic impedances (Z = ρc), some energy is reflected and some is transmitted (1)\n• The reflected pulses are detected by the transducer; the time delay gives the depth of the boundary (1)\n• The greater the difference in acoustic impedance between the two tissues, the greater the proportion of energy reflected — this provides contrast between different tissue types (1)` },
      { q: 'Describe how a PET scan works and state the type of radiation it detects.', marks: 3, markScheme: `• A positron-emitting radioactive tracer (e.g. fluorine-18 in FDG) is injected into the patient and accumulates in metabolically active tissue (1)\n• The emitted positron annihilates with a nearby electron, producing two gamma-ray photons (511 keV each) travelling in opposite directions (180° apart) (1)\n• Detectors around the patient detect the simultaneous arrival of these photon pairs (coincidence detection), allowing the computer to determine the location of the annihilation and build a 3D image (1)` },
      { q: 'Define acoustic impedance and state its equation and unit.', marks: 2, markScheme: `• Acoustic impedance Z = ρc where ρ is the density of the medium and c is the speed of sound in that medium (1)\n• Unit: kg m⁻² s⁻¹ (or Pa s m⁻¹ or rayl) (1)` },
      { q: 'Explain why gel is used between the ultrasound transducer and the patient\'s skin.', marks: 2, markScheme: `• The acoustic impedance of air is much lower than that of skin, so almost all the ultrasound would be reflected at an air-skin boundary (1)\n• The gel has an acoustic impedance similar to skin, providing good impedance matching so that most of the ultrasound energy is transmitted into the body (1)` },
      { q: 'Calculate the charge remaining on a 200 μF capacitor, initially charged to 10 V, after discharging through a 50 kΩ resistor for 20 s.', marks: 3, markScheme: `• τ = RC = 50 × 10³ × 200 × 10⁻⁶ = 10 s (1)\n• Q₀ = CV = 200 × 10⁻⁶ × 10 = 2.0 × 10⁻³ C (1)\n• Q = Q₀ e^(−t/τ) = 2.0 × 10⁻³ × e⁻² = 2.71 × 10⁻⁴ C ≈ 0.27 mC (1)` },
      { q: 'Two point charges of +3 μC and −5 μC are separated by 0.2 m. Calculate the force between them. (k = 8.99 × 10⁹ N m² C⁻²)', marks: 2, markScheme: `• F = kQ₁Q₂/r² = 8.99 × 10⁹ × 3 × 10⁻⁶ × 5 × 10⁻⁶ / 0.2² (1)\n• F = 3.37 N (attractive, since charges are opposite) (1)` },
      { q: 'A straight wire of length 0.4 m carries a current of 5 A at 30° to a magnetic field of 0.3 T. Calculate the force on the wire.', marks: 2, markScheme: `• F = BIL sin θ = 0.3 × 5 × 0.4 × sin 30° (1)\n• F = 0.3 N (1)` },
      { q: 'Explain the principle of a simple transformer and derive the transformer equation.', marks: 4, markScheme: `• An alternating current in the primary coil creates a changing magnetic field in the iron core (1)\n• The changing flux links with the secondary coil, inducing an EMF (by Faraday\'s law) (1)\n• For an ideal transformer: V_s/V_p = N_s/N_p (the ratio of voltages equals the ratio of turns) (1)\n• For an ideal transformer (no energy loss): V_p I_p = V_s I_s (power is conserved) (1)` },
      { q: 'A radioactive sample has an activity of 8000 Bq. Its half-life is 4 hours. Calculate the activity after 12 hours.', marks: 2, markScheme: `• 12 hours = 3 half-lives: A = A₀ × (½)³ = 8000 × 1/8 (1)\n• A = 1000 Bq (1)` },
      { q: 'Explain why binding energy per nucleon increases for nucleon numbers up to about 56 (iron) and then decreases.', marks: 3, markScheme: `• For small nuclei, adding more nucleons increases the strong force interactions more than the electrostatic repulsion, so BE per nucleon increases (1)\n• Iron-56 has the maximum BE per nucleon (~8.8 MeV) — it is the most stable nucleus (1)\n• For nuclei heavier than iron, the increasing electrostatic repulsion between protons (long-range) outweighs the additional strong force (short-range), so BE per nucleon decreases (1)` },
      { q: 'Describe the process of pair production and state the conditions for it to occur.', marks: 3, markScheme: `• A high-energy photon passes close to a nucleus and is converted into a particle-antiparticle pair (e.g. electron + positron) (1)\n• The photon must have energy at least equal to the combined rest mass energy of the two particles: E ≥ 2m₀c² = 2 × 0.511 MeV = 1.022 MeV for an electron-positron pair (1)\n• The nucleus is needed to conserve momentum — without it, momentum cannot be conserved in the creation of two particles from a single photon (1)` },
      { q: 'A parallel-plate capacitor has plate area 0.02 m² and plate separation 1 mm. The dielectric has permittivity ε = 4ε₀. Calculate the capacitance. (ε₀ = 8.85 × 10⁻¹² F m⁻¹)', marks: 2, markScheme: `• C = εA/d = 4 × 8.85 × 10⁻¹² × 0.02 / 1 × 10⁻³ (1)\n• C = 7.08 × 10⁻¹⁰ F ≈ 0.71 nF (1)` },
      { q: 'A charged particle moves in a circle in a magnetic field. Derive an expression for the radius of the path.', marks: 3, markScheme: `• The magnetic force provides the centripetal force: BQv = mv²/r (1)\n• Rearranging: r = mv/(BQ) (1)\n• The radius is proportional to momentum and inversely proportional to the magnetic flux density and charge (1)` },
      { q: 'Classify the following particles as hadrons or leptons: proton, electron, neutron, muon, pion.', marks: 2, markScheme: `• Hadrons (made of quarks): proton, neutron, pion (1)\n• Leptons (fundamental): electron, muon (1)` },
      { q: 'State what is meant by conservation of baryon number. Give an example of an allowed and a forbidden reaction.', marks: 3, markScheme: `• Baryon number is a quantum number: baryons have B = +1, antibaryons B = −1, non-baryons B = 0 (1)\n• In all particle interactions, the total baryon number before must equal the total baryon number after (1)\n• Allowed: p + n → p + p + π⁻ + n̄ — but must check baryon number: wait, simpler example: n → p + e⁻ + ν̄ₑ (B: 1 → 1 + 0 + 0 ✓). Forbidden: p → e⁺ + γ (B: 1 → 0 + 0 ✗) (1)` },
      { q: 'Discuss the relative advantages and disadvantages of X-ray, ultrasound, CT, and PET scanning for medical diagnosis.', marks: 8, markScheme: `• X-ray: fast, cheap, good for bones/dense structures; limited soft-tissue contrast; uses ionising radiation (1)\n• Ultrasound: no ionising radiation, real-time imaging, portable; poor resolution compared to CT/MRI, cannot image behind bone or gas (1)\n• CT: excellent cross-sectional and 3D imaging, good soft-tissue contrast; higher radiation dose than standard X-ray, more expensive (1)\n• PET: shows metabolic activity (functional imaging) rather than just structure; useful for detecting cancers; uses radioactive tracers, expensive, lower spatial resolution (1)\n• X-rays and CT use ionising radiation which carries a small risk of causing cancer — dose should be minimised (1)\n• Ultrasound is considered safest and is preferred for imaging fetuses and soft tissues where possible (1)\n• CT provides more detailed structural images than X-ray but at a higher radiation dose — used when detailed 3D anatomy is needed (1)\n• PET is uniquely useful for functional imaging but is often combined with CT (PET-CT) for better anatomical localisation (1)` },
      { q: 'Explain why capacitors are used in timing circuits and describe how the time constant affects the charging/discharging behaviour.', marks: 3, markScheme: `• Capacitors charge and discharge at predictable, exponential rates determined by the time constant τ = RC (1)\n• A larger time constant means slower charging/discharging — the RC combination acts as a timer (1)\n• After 5 time constants, the capacitor is effectively fully charged (>99%) or fully discharged (<1%) — this defines the timing interval (1)` },
      { q: 'Describe the electric field pattern between two parallel plates with a uniform PD between them.', marks: 2, markScheme: `• The field lines are straight, parallel, and equally spaced — running from the positive plate to the negative plate (1)\n• The field is uniform (constant E = V/d) throughout the region between the plates, except for edge effects at the boundaries (1)` },
      { q: 'Compare the electric field due to a point charge with the gravitational field due to a point mass.', marks: 4, markScheme: `• Both follow inverse-square laws: F ∝ 1/r² (1)\n• Both have radial field patterns around the source (1)\n• Gravitational fields are always attractive (mass is always positive); electric fields can be attractive or repulsive depending on the signs of the charges (1)\n• Gravitational field strength g = GM/r²; electric field strength E = kQ/r² — the equations are analogous in form (1)` },
    ],
  },

};
